            entry.value.firstOrNull()?.let { value ->
                put(entry.key, JsonPrimitive(value))
            }
        }
    }
    return ApiJson.decodeFromJsonElement(serializer, element)
}

private suspend fun <T> respondSuccess(
    call: ApplicationCall,
    data: T,
    serializer: KSerializer<T>,
    envelope: ApiResponseEnvelope,
    mediaType: String,
) {
    val body = encodeSuccessBody(data, serializer, envelope, mediaType)
    call.respondText(body, contentType = contentType(mediaType))
}

private fun <T> encodeSuccessBody(
    data: T,
    serializer: KSerializer<T>,
    envelope: ApiResponseEnvelope,
    mediaType: String,
): String {
    if (mediaType != "application/json") {
        return data?.toString().orEmpty()
    }
    val payload = if (serializer.descriptor.serialName == "kotlin.Unit") {
        JsonNull
    } else {
        ApiJson.encodeToJsonElement(serializer, data)
    }
    if (envelope.kind == "none") {
        return payload.toString()
    }
    if (envelope.kind == "code_message_data") {
        return buildJsonObject {
            put(envelope.fields.code, JsonPrimitive(envelope.successCode))
            put(envelope.fields.message, JsonPrimitive(envelope.successMessage))
            put(envelope.fields.data, payload)
        }.toString()
    }
    if (envelope.kind == "ok_data_error") {
        return buildJsonObject {
            put(envelope.fields.ok, JsonPrimitive(true))
            put(envelope.fields.data, payload)
        }.toString()
    }
    return payload.toString()
}

private suspend fun respondApiError(
    call: ApplicationCall,
    error: ApiError,
    envelope: ApiResponseEnvelope,
    routeId: String,
) {
    val payload = normalizeApiErrorPayload(error.payload, routeId)
    val body = encodeErrorBody(payload, envelope)
    val status = if (envelope.kind == "none") HttpStatusCode.InternalServerError else HttpStatusCode.OK
    call.respondText(body, contentType = ContentType.Application.Json, status = status)
}

private fun encodeErrorBody(payload: ApiErrorPayload, envelope: ApiResponseEnvelope): String {
    val payloadElement = ApiJson.encodeToJsonElement(ApiErrorPayload.serializer(), payload)
    if (envelope.kind == "code_message_data") {
        return buildJsonObject {
            put(envelope.fields.code, JsonPrimitive(payload.code))
            put(envelope.fields.message, JsonPrimitive(payload.message))
            put(envelope.fields.data, JsonNull)
            if (envelope.errorIdentity != "none") {
                put(envelope.fields.error, payloadElement)
            }
        }.toString()
    }
    if (envelope.kind == "ok_data_error") {
        return buildJsonObject {
            put(envelope.fields.ok, JsonPrimitive(false))
            put(envelope.fields.error, payloadElement)
        }.toString()
    }
    return payloadElement.toString()
}

private fun normalizeApiErrorPayload(payload: ApiErrorPayload, routeId: String): ApiErrorPayload {
    val entry = lookupApiError(payload, routeId)
    val code = if (payload.code != 0) payload.code else entry?.code ?: 0
    val message = payload.message.ifBlank { entry?.message ?: "API error $code" }
    val toast = payload.toast
    return ApiErrorPayload(
        id = payload.id.ifBlank { entry?.id.orEmpty() },
        group = payload.group.ifBlank { entry?.group.orEmpty() },
        key = payload.key.ifBlank { entry?.key.orEmpty() },
        code = code,
        message = message,
        toast = ApiToastPayload(
            key = toast.key.ifBlank { entry?.toast?.key.orEmpty() },
            level = toast.level.ifBlank { entry?.toast?.level ?: "error" },
            default = toast.default.ifBlank { entry?.toast?.default ?: message },
            text = toast.text,
        ),
    )
}

private fun closePayload(code: Int? = null, reason: String? = null): JsonElement =
    buildJsonObject {
        if (code != null) {
            put("code", JsonPrimitive(code))
        }
        if (reason != null) {
            put("reason", JsonPrimitive(reason))
        }
    }

private fun contentType(mediaType: String): ContentType =
    if (mediaType == "application/json") ContentType.Application.Json else ContentType.parse(mediaType)
